import multiprocessing

memo = {0: 0, 1: 1}

def fib(n, memo=memo):
    if n in memo:
        return memo[n]
    memo[n] = fib(n-1, memo) + fib(n-2, memo)
    return memo[n]

def parallel_fib(numbers):
    with multiprocessing.Pool() as pool:
        results = pool.map(fib, numbers)
    return results

inputs = [35, 36, 37]
print(parallel_fib(inputs))

